document.getElementById('btn').addEventListener('click', function() {
  let input = document.getElementById('taille');
  let newSize = parseInt(input.value);
  let carre = document.getElementById('carre');
  let message = document.getElementById('message');

  if (isNaN(newSize) || newSize < 50 || newSize > 500) {
    message.textContent = 'La taille doit être comprise entre 50 et 500 pixels.';
  } else {
    carre.style.width = newSize + 'px';
    carre.style.height = newSize + 'px';
    message.textContent = '';
  }
});

